function toObject(value) {
    return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function parsePayload(payload) {
    if (!payload) return {};
    if (typeof payload === "string") {
        try { return JSON.parse(payload); } catch (err) { return {}; }
    }
    if (Buffer.isBuffer(payload)) {
        try { return JSON.parse(payload.toString()); } catch (err) { return {}; }
    }
    return toObject(payload);
}

function toNumber(value, fallback) {
    const n = Number(value);
    return Number.isFinite(n) ? n : fallback;
}

function normalizeRisk(value, fallback) {
    const risk = String(value || "").trim().toLowerCase();
    if (["critical", "degraded", "high"].includes(risk)) return "high";
    if (["moderate", "unstable", "medium", "attention"].includes(risk)) return "medium";
    if (["stable", "normal", "low"].includes(risk)) return "low";
    return fallback || "low";
}

function normalizeLoss(value, losses, oee) {
    const direct = String(value || "").trim().toLowerCase();
    if (direct) return direct;
    if (Array.isArray(losses) && losses.length) {
        return String(losses[0]?.dominantDimension || losses[0]?.dominantLoss || losses[0]?.loss || "").trim().toLowerCase();
    }
    const availability = toNumber(oee?.availability, 1);
    const performance = toNumber(oee?.performance, 1);
    const quality = toNumber(oee?.quality, 1);
    const lossMap = {
        availability: 1 - availability,
        performance: 1 - performance,
        quality: 1 - quality
    };
    return Object.entries(lossMap).sort((a, b) => b[1] - a[1])[0]?.[0] || "";
}

function getOee(payload) {
    return toNumber(
        payload?.globalOEE?.oee ??
        payload?.globalOEE?.current ??
        payload?.oee?.oee ??
        payload?.oee?.current ??
        payload?.oeeGlobal ??
        payload?.globalOEE,
        0
    );
}

function mean(values) {
    const clean = values.filter((value) => Number.isFinite(value));
    if (!clean.length) return 0;
    return clean.reduce((sum, value) => sum + value, 0) / clean.length;
}

function slope(values) {
    const clean = values.filter((value) => Number.isFinite(value));
    const n = clean.length;
    if (n < 2) return 0;
    const meanX = (n - 1) / 2;
    const meanY = mean(clean);
    let numerator = 0;
    let denominator = 0;
    for (let i = 0; i < n; i += 1) {
        numerator += (i - meanX) * (clean[i] - meanY);
        denominator += Math.pow(i - meanX, 2);
    }
    return denominator ? numerator / denominator : 0;
}

function round(value, decimals) {
    const numeric = Number(value);
    if (!Number.isFinite(numeric)) return 0;
    const factor = Math.pow(10, decimals || 4);
    return Math.round(numeric * factor) / factor;
}

function countTrailing(history, predicate) {
    let count = 0;
    for (let i = history.length - 1; i >= 0; i -= 1) {
        if (!predicate(history[i])) break;
        count += 1;
    }
    return count;
}

function hasIntervention(entry) {
    const action = String(entry?.action || "").toLowerCase();
    return action && !["maintain", "maintain_current_plan", "preserve_recovery", "maintain_local_plan"].includes(action);
}

function classifyInterventionEffectiveness(history, recentMeanOEE, oeeSlope) {
    const recent = history.slice(-5);
    const interventionEvents = recent.filter(hasIntervention);
    if (!interventionEvents.length) return "neutral";
    const first = interventionEvents[0];
    const delta = recentMeanOEE - Number(first.oee || 0);
    if (delta >= 0.015 || oeeSlope > 0.004) return "improving";
    if (delta <= 0.003 && oeeSlope <= 0.001) return "low_response";
    return "neutral";
}

function strategyForState(temporalState) {
    const map = {
        stable_cell: { adaptiveAction: "maintain_current_plan", strategyClass: "reactive" },
        degrading_cell: { adaptiveAction: "coordinated_attention", strategyClass: "adaptive" },
        recovering_cell: { adaptiveAction: "preserve_recovery", strategyClass: "adaptive" },
        chronic_loss_cell: { adaptiveAction: "contain_persistent_loss", strategyClass: "adaptive" },
        persistent_critical_cps: { adaptiveAction: "escalate_local_recovery", strategyClass: "escalated" },
        low_response_to_local_intervention: { adaptiveAction: "structural_local_intervention", strategyClass: "escalated" }
    };
    return map[temporalState] || map.stable_cell;
}

function buildSignals(history, windowSize) {
    const values = history.map((entry) => Number(entry.oee)).filter((value) => Number.isFinite(value));
    const recentValues = values.slice(-4);
    const current = history[history.length - 1] || {};
    const currentLoss = String(current.dominantLoss || "").toLowerCase();
    const currentCps = String(current.criticalCps || "").toLowerCase();
    const recentMeanOEE = mean(recentValues);
    const oeeSlope = slope(values.slice(-6));
    const riskPersistence = countTrailing(history, (entry) => entry.riskLevel === "high");
    const dominantLossPersistence = currentLoss
        ? countTrailing(history, (entry) => String(entry.dominantLoss || "").toLowerCase() === currentLoss)
        : 0;
    const criticalCpsPersistence = currentCps
        ? countTrailing(history, (entry) => String(entry.criticalCps || "").toLowerCase() === currentCps)
        : 0;
    const interventionEffectiveness = classifyInterventionEffectiveness(history, recentMeanOEE, oeeSlope);

    let temporalState = "stable_cell";
    let adaptiveReason = "No persistent local adaptive pattern detected in the current window.";

    if (interventionEffectiveness === "low_response") {
        temporalState = "low_response_to_local_intervention";
        adaptiveReason = "Recent local interventions did not produce measurable OEE recovery.";
    } else if (criticalCpsPersistence >= 3) {
        temporalState = "persistent_critical_cps";
        adaptiveReason = "The same local CPS remained critical across at least three recent events.";
    } else if (dominantLossPersistence >= 4) {
        temporalState = "chronic_loss_cell";
        adaptiveReason = "The same local dominant loss repeated across at least four recent events.";
    } else if (oeeSlope < -0.004 && riskPersistence >= 2) {
        temporalState = "degrading_cell";
        adaptiveReason = "Local OEE slope is negative while local risk remains elevated.";
    } else if (oeeSlope > 0.004 && recentMeanOEE >= 0.6) {
        temporalState = "recovering_cell";
        adaptiveReason = "Local OEE is improving across the recent adaptive window.";
    }

    const strategy = strategyForState(temporalState);
    return {
        temporalState,
        adaptiveAction: strategy.adaptiveAction,
        strategyClass: strategy.strategyClass,
        interventionEffectiveness,
        adaptiveReason,
        historyWindow: windowSize,
        recentMeanOEE: round(recentMeanOEE, 4),
        oeeSlope: round(oeeSlope, 5),
        riskPersistence,
        dominantLossPersistence,
        criticalCpsPersistence
    };
}

function buildTimeline(history, limit) {
    return history.slice(-limit).reverse().map((entry) => ({
        ts: entry.ts || null,
        timestamp: entry.timestamp || "",
        temporalState: entry.temporalState || "",
        adaptiveAction: entry.adaptiveAction || "",
        strategyClass: entry.strategyClass || "",
        interventionEffectiveness: entry.interventionEffectiveness || ""
    }));
}

const inputTopic = msg.topic;
const payload = parsePayload(msg.payload);
const acsmId = "acsm2";
const windowSize = 10;
const now = Date.now();
const timestamp = payload.timestamp || new Date(now).toISOString();
const sourceTs = toNumber(payload.ts || Date.parse(timestamp), now);
const oee = getOee(payload);
const reasoning = toObject(payload.reasoning || payload.systemReasoning);
const forecast = toObject(payload.systemForecast || payload.predictedRisk);
const critical = toObject(payload.criticalCPS || payload.criticalCps || payload.bottleneck);
const dominantLoss = normalizeLoss(
    reasoning.dominantLoss || payload.dominantLoss || payload.dominantLossNow,
    payload.dominantLosses,
    payload.globalOEE || payload.oee
);
const riskLevel = normalizeRisk(payload.riskLevel || reasoning.riskLevel || forecast.risk || forecast.level, oee < 0.6 ? "high" : oee < 0.75 ? "medium" : "low");
const criticalCps = String(critical.cpsId || payload.criticalCps || payload.bottleneckCps || "");
const action = String(payload.recommendation || reasoning.recommendation || payload.actionPlan?.recommendedAction || payload.actionPlan?.actionType || (riskLevel === "high" ? "stabilize" : "maintain"));
const systemState = String(reasoning.systemState || payload.systemState?.health || payload.systemState || (riskLevel === "high" ? "critical" : riskLevel === "medium" ? "attention" : "stable"));

const historyKey = acsmId + "_local_history";
const previousHistory = Array.isArray(global.get(historyKey)) ? global.get(historyKey) : [];
let history = previousHistory.concat({
    ts: sourceTs,
    timestamp,
    oee,
    riskLevel,
    dominantLoss,
    criticalCps,
    action,
    systemState
}).slice(-windowSize);

const adaptiveLearningLocal = buildSignals(history, windowSize);
history = history.map((entry, index) => {
    if (index !== history.length - 1) return entry;
    return Object.assign({}, entry, {
        temporalState: adaptiveLearningLocal.temporalState,
        adaptiveAction: adaptiveLearningLocal.adaptiveAction,
        strategyClass: adaptiveLearningLocal.strategyClass,
        interventionEffectiveness: adaptiveLearningLocal.interventionEffectiveness
    });
});
global.set(historyKey, history);
const adaptiveTimelineLocal = buildTimeline(history, 8);

msg.topic = acsmId + "/local/adaptive";
msg.payload = {
    schemaVersion: "1.0",
    messageType: "acsm_local_adaptive_intelligence",
    source: acsmId,
    level: "level2",
    ts: now,
    timestamp: new Date(now).toISOString(),
    basedOn: {
        topic: inputTopic || acsmId + "/level2/intelligence",
        sourceTs
    },
    localAssessment: {
        oee,
        riskLevel,
        dominantLoss,
        criticalCps,
        action,
        systemState
    },
    adaptiveLearningLocal,
    adaptiveTimelineLocal
};

node.status({ fill: adaptiveLearningLocal.strategyClass === "escalated" ? "red" : adaptiveLearningLocal.strategyClass === "adaptive" ? "yellow" : "green", shape: "dot", text: adaptiveLearningLocal.temporalState + " | n=" + history.length });
return msg;
